import type * as DMMF from '@prisma/dmmf'
import { DMMFHelper } from './dmmf'

function inputObjectType(name: string, fields: DMMF.SchemaArg[]): DMMF.InputType {
  return {
    name,
    fields,
    constraints: { minNumFields: null, maxNumFields: null },
  }
}

function dmmf(inputObjectTypes: DMMF.InputType[]) {
  return new DMMFHelper({
    schema: {
      inputObjectTypes: { prisma: inputObjectTypes },
      outputObjectTypes: { prisma: [...], model: [] },
      enumTypes: { prisma: [] },
      fieldRefTypes: { prisma: [] },
