import { Generator, GeneratorConfig, GeneratorManifest, GeneratorOptions } from '@prisma/generator'

export class YourGenerator implements Generator {
  readonly name = 'your-generator-name'

  async getManifest(config: GeneratorConfig): Promise<GeneratorManifest> {
    return {
      defaultOutput: './generated',
      prettyName: 'Your Generator',
      version: '1.0.0',
      requiresEngines: [],
      requiresEngineVersion: 'engineVersionHere',
    }
  }

  async generate(options: GeneratorOptions): Promise<void> {
    const outputDir = parseEnvValue(options.generator.output!)

    // Access DMMF data:
    const models = options.datamodel.models
    const enums = options.datamodel.enums

    // Generate code using ts-builders
    const file = file()
    const myInterface = interfaceDeclaration('MyInterface')
      .add(property('id', namedType('string')))

    file.add(myInterface)

    // Write output
    await fsPromises.writeFile(
      path.join(outputDir, 'generated.ts'),
      stringify(file),
    )
  }
}
```

