```typescript
// All builders extend TypeBuilder or implement BasicBuilder
// They use a fluent API with .write(writer) method

// Example 1: Interface (src/Interface.ts, lines 10-71)
export class InterfaceDeclaration extends TypeBuilder {
  constructor(readonly name: string) {}
  add(item: InterfaceItem): this { ... }  // Add properties/methods
  addGenericParameter(param: GenericParameter) { ... }
  extends(type: NamedType) { ... }
  write(writer: Writer): void { ... }  // Generates output
}

// Example 2: Property (src/Property.ts, lines 9-57)
export class Property implements BasicBuilder {
  constructor(private name: string | WellKnownSymbol, private type: TypeBuilder) {}
  optional(): this { ... }
  readonly(): this { ... }
  write(writer: Writer): void { ... }
}

// Example 3: Method (src/Method.ts, lines 9-60)
export class Method implements BasicBuilder {
  constructor(private name: string) {}
  setReturnType(returnType: TypeBuilder): this { ... }
  addParameter(param: Parameter): this { ... }
  addGenericParameter(param: GenericParameter): this { ... }
  write(writer: Writer): void { ... }
}
