│   │   │   ├── ModelFile.ts
│   │   │   ├── EnumsFile.ts
│   │   │   ├── ClientFile.ts
│   │   │   └── ...
│   │   ├── Model.ts          # Generates types for a single model
│   │   └── ...
│   ├── typedSql/
│   └── utils/
├── dist/                     # Compiled output
├── tests/
└── helpers/
    └── build.ts
```

---

### **5. THE STANDARD GENERATOR PATTERN**

**Step 1: Create Generator Class**
```typescript
// src/generator.ts
import { Generator, GeneratorConfig, GeneratorManifest, GeneratorOptions } from '@prisma/generator'

export class MyCustomGenerator implements Generator {
  readonly name = 'my-custom-generator'

  async getManifest(config: GeneratorConfig): Promise<GeneratorManifest> {
    return {
      defaultOutput: './generated',
      prettyName: 'My Custom Generator',
      version: '1.0.0',
      requiresEngines: [],
      requiresEngineVersion: '...',
    }
  }

  async generate(options: GeneratorOptions): Promise<void> {
    const { dmmf, outputDir } = options

    // Generate files from DMMF
    // Write to outputDir
  }
}
```

**Step 2: Wire up generatorHandler**
```typescript
// src/index.ts or bin.ts
import { generatorHandler } from '@prisma/generator-helper'
import { MyCustomGenerator } from './generator'

const generator = new MyCustomGenerator()

generatorHandler({
  onManifest(config) {
    return generator.getManifest(config)
  },
  onGenerate(options) {
    return generator.generate(options)
  },
})
```

**Step 3: Write files to outputDir**
- Create a FileMap structure: `{ [fileName]: string | Buffer | FileMap }`
- Use recursion for nested directories
- Write recursively to disk:

```typescript
async function writeFileMap(outputDir: string, fileMap: FileMap) {
  for (const [fileName, content] of Object.entries(fileMap)) {
    const absolutePath = path.join(outputDir, fileName)
    if (typeof content === 'string' || Buffer.isBuffer(content)) {
      await fs.writeFile(absolutePath, content)
    } else {
      await fs.mkdir(absolutePath)
      await writeFileMap(absolutePath, content)
    }
  }
}
```

---

### **6. HOW EXISTING GENERATORS WORK**

**client-generator-ts implementation example:**

1. **PrismaClientTsGenerator.generate()** receives `GeneratorOptions`
2. Creates a **DMMFHelper** to cache and index DMMF data
3. Instantiates **TSClient** with configuration
4. **TSClient.generateClientFiles()** orchestrates file generation:
   - Iterates over all models in `dmmf.datamodel.models`
   - For each model, creates:
     - `ModelFile` - Type definitions for that model
     - Custom types (Input, Output, Args)
   - Also generates:
     - `EnumsFile` - All enums
     - `ClientFile` - Main PrismaClient
     - `ModelsFile` - Re-exports of all models
     - `PrismaNamespaceFile` - Prisma namespace exports
5. Returns a nested **FileMap** structure
6. Writes recursively to disk

**File Generator Pattern** (see ModelFile.ts):
```typescript
export function createModelFile(context: GenerateContext, modelName: string): string {
  const model = context.dmmf.typeAndModelMap[modelName]
  const model = new Model(model, context)  // Transform DMMF to TypeScript
  return model.toTS()  // Generate string of TypeScript code
}
```

---

### **7. KEY FILES TO UNDERSTAND**

| Package | Key Files | Purpose |
|---------|-----------|---------|
| `generator-helper` | `src/generatorHandler.ts`, `src/json-rpc.ts`, `src/GeneratorProcess.ts` | JSON-RPC protocol, handler setup |
| `@prisma/generator` | `src/generator.ts`, `src/configuration.ts` | Type definitions for Generator interface |
| `@prisma/dmmf` | `src/dmmf.ts` | DMMF type definitions (models, fields, enums, etc.) |
| `client-generator-ts` | `src/generator.ts`, `src/generateClient.ts`, `src/TSClient/TSClient.ts` | Orchestrates file generation for TS |
| `client-generator-ts` | `src/dmmf.ts` | **DMMFHelper** - Caches/indexes DMMF for fast access |
| `client-generator-ts` | `src/TSClient/file-generators/*.ts` | Individual file generators |

---

### **8. PACKAGE.JSON SETUP**

From `client-generator-ts/package.json`:
```json
{
  "name": "@prisma/my-custom-generator",
  "main": "dist/index.js",
  "exports": {
    ".": {
      "require": { "default": "./dist/index.js" },
      "import": { "default": "./dist/index.mjs" }
    }
  },
  "dependencies": {
    "@prisma/generator": "workspace:*",
    "@prisma/dmmf": "workspace:*",
    "@prisma/debug": "workspace:*"
  },
  "scripts": {
    "build": "tsx helpers/build.ts",
    "dev": "DEV=true tsx helpers/build.ts"
  }
}
```

---

### **9. PRACTICAL GENERATOR EXAMPLES**

**Minimal example** (from test fixture):
```typescript
import { generatorHandler } from '@prisma/generator-helper'

generatorHandler({
  onManifest() {
    return {
      defaultOutput: '.',
      prettyName: 'My Generator',
    }
  },

  onGenerate(options) {
    const { dmmf, outputDir } = options

    // Access all models
    for (const model of dmmf.datamodel.models) {
      console.log(`Model: ${model.name}`)
      for (const field of model.fields) {
        console.log(`  - ${field.name}: ${field.type}`)
      }
    }

    return Promise.resolve()
  },
})
```

**Generator with dependencies** (from test fixture):
```typescript
generatorHandler({
  onManifest() {
    return {
      defaultOutput: 'my-generator-output',
      prettyName: 'I depend on the client',
      requiresEngines: [],
      requiresGenerators: ['prisma-client-js'],  // Wait for this first
    }
  },
  async onGenerate(options) {
    // Will be called only after prisma-client-js generation
  },
})
```

---

### **File Locations Summary**

- **Generator Helper Core:** `/packages/generator-helper/src/`
  - `generatorHandler.ts` - JSON-RPC protocol
  - `json-rpc.ts` - Message types

- **Type Definitions:**
  - `@prisma/generator` - `/packages/generator/src/`
  - `@prisma/dmmf` - `/packages/dmmf/src/dmmf.ts`

- **Working Implementations:**
  - TypeScript Generator: `/packages/client-generator-ts/src/`
  - JavaScript Generator: `/packages/client-generator-js/src/`
  - Adapter (for Studio): `/packages/client/src/generation/generator.ts`

This architecture gives you everything needed to create a new generator that follows the standard Prisma patterns!

