import type * as DMMF from '@prisma/dmmf'

/**
 * Maps a DMMF scalar type name to its TypeScript equivalent in a REST API context.
 * DateTime is represented as a string (ISO 8601) since JSON has no native date type.
 * Bytes is represented as a string (base64).
 */
export function dmmfTypeToTs(dmmfType: string): string {
  switch (dmmfType) {
    case 'String':
      return 'string'
    case 'Int':
    case 'Float':
    case 'Decimal':
      return 'number'
    case 'Boolean':
      return 'boolean'
    case 'DateTime':
      return 'string'
    case 'BigInt':
      return 'bigint'
    case 'Json':
      return 'unknown'
    case 'Bytes':
      return 'string'
    default:
      // Enums and any unrecognised types are referenced by their name directly
      return dmmfType
  }
}

/**
 * Formats a field's TypeScript type, including the list modifier if needed.
 */
export function fieldToTsType(field: DMMF.Field): string {
  const base = dmmfTypeToTs(field.type)
  return field.isList ? `${base}[]` : base
}

/**
 * Returns only the scalar and enum fields of a model, excluding relation
 * and unsupported fields that cannot be serialised over a REST API.
 */
export function getScalarAndEnumFields(fields: readonly DMMF.Field[]): DMMF.Field[] {
  return fields.filter((f) => f.kind === 'scalar' || f.kind === 'enum')
}

/**
 * Returns fields that form the unique identifier set of a model —
 * i.e. fields marked with @id or @unique. These are used in WhereUniqueInput.
 */
export function getUniqueFields(fields: readonly DMMF.Field[]): DMMF.Field[] {
  return (fields as DMMF.Field[]).filter((f) => (f.isId || f.isUnique) && (f.kind === 'scalar' || f.kind === 'enum'))
}

/**
 * Returns the subset of scalar/enum fields that are appropriate for a CreateInput
 * type: excludes auto-generated IDs, read-only fields, and @updatedAt fields.
 */
export function getCreateInputFields(fields: readonly DMMF.Field[]): DMMF.Field[] {
  return getScalarAndEnumFields(fields).filter((f) => !f.isReadOnly && !f.isGenerated && !f.isUpdatedAt)
}

/**
 * Converts a PascalCase or camelCase model name to a lowercase, hyphenated
 * resource path segment suitable for REST URLs (e.g. "BlogPost" → "blog-posts").
 */
export function modelNameToResourcePath(modelName: string): string {
  return (
    modelName
      // Insert a hyphen before each uppercase letter that follows a lowercase letter or digit
      .replace(/([a-z0-9])([A-Z])/g, '$1-$2')
      .toLowerCase() + 's'
  )
}

/**
 * Converts a PascalCase model name to a camelCase property key for the root
 * RestApiClient class (e.g. "BlogPost" → "blogPosts", "User" → "users").
