import type * as DMMF from '@prisma/dmmf'

import { modelNameToPropertyKey, modelNameToResourcePath } from './dmmf-helpers'

/**
 * Generates a `{Model}RestClient` class whose CRUD methods map to the
 * conventional REST endpoints for a given resource:
 *
 *   GET    /{resource}          → findMany
 *   GET    /{resource}/:id      → findUnique
 *   POST   /{resource}          → create
 *   PUT    /{resource}/:id      → update
 *   DELETE /{resource}/:id      → delete
 */
export function generateModelClient(model: DMMF.Model): string {
  const name = model.name
  const resource = modelNameToResourcePath(name)

  return `export class ${name}RestClient {
  constructor(private readonly baseUrl: string) {}

  async findMany(params?: { skip?: number; take?: number; [key: string]: unknown }): Promise<${name}[]> {
    const qs = params !== undefined ? '?' + new URLSearchParams(params as Record<string, string>).toString() : ''
    const res = await fetch(\`\${this.baseUrl}/${resource}\${qs}\`)
    if (!res.ok) throw new Error(\`${name}.findMany failed: \${res.status} \${res.statusText}\`)
    return res.json() as Promise<${name}[]>
  }

  async findUnique(args: { where: ${name}WhereUniqueInput }): Promise<${name} | null> {
    const id = Object.values(args.where).find((v) => v !== undefined)
    if (id === undefined) throw new Error('${name}.findUnique requires at least one field in \`where\`')
    const res = await fetch(\`\${this.baseUrl}/${resource}/\${encodeURIComponent(String(id))}\`)
    if (res.status === 404) return null
    if (!res.ok) throw new Error(\`${name}.findUnique failed: \${res.status} \${res.statusText}\`)
    return res.json() as Promise<${name}>
  }

  async create(args: { data: ${name}CreateInput }): Promise<${name}> {
    const res = await fetch(\`\${this.baseUrl}/${resource}\`, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(args.data),
    })
    if (!res.ok) throw new Error(\`${name}.create failed: \${res.status} \${res.statusText}\`)
    return res.json() as Promise<${name}>
  }

  async update(args: { where: ${name}WhereUniqueInput; data: ${name}UpdateInput }): Promise<${name}> {
    const id = Object.values(args.where).find((v) => v !== undefined)
    if (id === undefined) throw new Error('${name}.update requires at least one field in \`where\`')
    const res = await fetch(\`\${this.baseUrl}/${resource}/\${encodeURIComponent(String(id))}\`, {
      method: 'PUT',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(args.data),
    })
    if (!res.ok) throw new Error(\`${name}.update failed: \${res.status} \${res.statusText}\`)
    return res.json() as Promise<${name}>
  }

  async delete(args: { where: ${name}WhereUniqueInput }): Promise<${name}> {
    const id = Object.values(args.where).find((v) => v !== undefined)
    if (id === undefined) throw new Error('${name}.delete requires at least one field in \`where\`')
    const res = await fetch(\`\${this.baseUrl}/${resource}/\${encodeURIComponent(String(id))}\`, {
      method: 'DELETE',
    })
    if (!res.ok) throw new Error(\`${name}.delete failed: \${res.status} \${res.statusText}\`)
    return res.json() as Promise<${name}>
  }
}`
}

/**
 * Returns the camelCase plural property name used on the root `RestApiClient`
 * for a given model.
 */
export { modelNameToPropertyKey }

