import type * as DMMF from '@prisma/dmmf'

import { modelNameToPropertyKey } from './dmmf-helpers'

/**
 * Generates the root `RestApiClient` class that aggregates individual model
 * clients into a single entry-point for consumers.
 *
 * Example usage of the generated class:
 * ```ts
 * const client = new RestApiClient('https://api.example.com')
 * const users = await client.users.findMany()
 * ```
 */
export function generateMainClient(models: readonly DMMF.Model[]): string {
  if (models.length === 0) {
    return `export class RestApiClient {
  constructor(_baseUrl: string) {}
}`
  }

  const propertyDeclarations = models
    .map((m) => `  readonly ${modelNameToPropertyKey(m.name)}: ${m.name}RestClient`)
    .join('\n')

  const assignments = models
    .map((m) => `    this.${modelNameToPropertyKey(m.name)} = new ${m.name}RestClient(normalizedBase)`)
    .join('\n')

  return `export class RestApiClient {
${propertyDeclarations}

  constructor(baseUrl: string) {
    const normalizedBase = baseUrl.replace(/\\/$/, '')
${assignments}
  }
}`
}

