import fs from 'node:fs/promises'
import path from 'node:path'

import type * as DMMF from '@prisma/dmmf'

import { generateMainClient } from './generate-main-client'
import { generateModelClient } from './generate-model-client'
import { generateEnumType, generateModelTypes } from './generate-model-types'

export type GenerateRestClientOptions = {
  dmmf: DMMF.Document
  outputDir: string
}

const FILE_HEADER = `\
// This file was generated by @prisma/rest-api-client-generator.
// Do not edit it manually — re-run \`prisma generate\` to regenerate.
/* eslint-disable */
`

/**
 * Orchestrates code generation for the REST API client:
 *
 * - Writes one `{kebab-case-model}.ts` file per model containing its type
 *   interfaces and the model-specific REST client class.
 * - Writes an `index.ts` that imports all model files, declares the root
 *   `RestApiClient` class, and re-exports every type for convenience.
 * - Writes an `enums.ts` (only when the schema contains enums).
 */
export async function generateRestClient({ dmmf, outputDir }: GenerateRestClientOptions): Promise<void> {
  await fs.mkdir(outputDir, { recursive: true })

  const { models, enums } = dmmf.datamodel

  // ── enums.ts ──────────────────────────────────────────────────────────────
  if (enums.length > 0) {
    const enumsContent = [FILE_HEADER, ...enums.map((e) => generateEnumType(e))].join('\n')
    await fs.writeFile(path.join(outputDir, 'enums.ts'), enumsContent, 'utf-8')
  }

  // ── {model}.ts files ──────────────────────────────────────────────────────
  const modelFilenames: Map<string, string> = new Map()

  for (const model of models) {
    const filename = toKebabCase(model.name) + '.ts'
    modelFilenames.set(model.name, filename)

    // Determine which enums this model references so we can import them
    const referencedEnumNames = [
      ...new Set(model.fields.filter((f) => f.kind === 'enum').map((f) => f.type)),
    ]

    const lines: string[] = [FILE_HEADER]

    if (referencedEnumNames.length > 0) {
      lines.push(`import type { ${referencedEnumNames.join(', ')} } from './enums'`)
      lines.push(`export type { ${referencedEnumNames.join(', ')} } from './enums'`)
      lines.push('')
    }

    lines.push(generateModelTypes(model))
    lines.push('')
    lines.push(generateModelClient(model))
    lines.push('')

    await fs.writeFile(path.join(outputDir, filename), lines.join('\n'), 'utf-8')
  }

  // ── index.ts ──────────────────────────────────────────────────────────────
  const indexLines: string[] = [FILE_HEADER]

  if (enums.length > 0) {
    const allEnumNames = enums.map((e) => e.name).join(', ')
    indexLines.push(`export type { ${allEnumNames} } from './enums'`)
  }

  for (const model of models) {
    const filename = './' + modelFilenames.get(model.name)!.replace(/\.ts$/, '')
    indexLines.push(`export type { ${model.name}, ${model.name}CreateInput, ${model.name}UpdateInput, ${model.name}WhereUniqueInput } from '${filename}'`)
    indexLines.push(`export { ${model.name}RestClient } from '${filename}'`)
  }

  if (models.length > 0) {
    indexLines.push('')
    // Import all client classes for use in RestApiClient
    for (const model of models) {
      const filename = './' + modelFilenames.get(model.name)!.replace(/\.ts$/, '')
      indexLines.push(`import { ${model.name}RestClient } from '${filename}'`)
    }
    indexLines.push('')
    indexLines.push(generateMainClient(models))
  } else {
    indexLines.push('')
    indexLines.push(generateMainClient(models))
  }

  indexLines.push('')
  await fs.writeFile(path.join(outputDir, 'index.ts'), indexLines.join('\n'), 'utf-8')
}

function toKebabCase(name: string): string {
  return name
    .replace(/([a-z0-9])([A-Z])/g, '$1-$2')
    .toLowerCase()
}

