    expect(files.sort()).toEqual(['enums.ts', 'index.ts', 'post.ts', 'user.ts'])
  })

  test('index.ts re-exports all types and declares RestApiClient', async () => {
    await generateRestClient({
      dmmf: makeDocument([USER_MODEL]),
      outputDir: tmpDir,
    })

    const indexContent = await fs.readFile(path.join(tmpDir, 'index.ts'), 'utf-8')
    expect(indexContent).toContain('export type { User')
    expect(indexContent).toContain('export { UserRestClient }')
    expect(indexContent).toContain('export class RestApiClient')
    expect(indexContent).toContain('readonly users: UserRestClient')
  })

  test('enums.ts is written only when there are enums', async () => {
    await generateRestClient({
      dmmf: makeDocument([POST_MODEL], []),
      outputDir: tmpDir,
    })

    const files = await fs.readdir(tmpDir)
    expect(files).not.toContain('enums.ts')
  })

  test('model file imports enum types from enums.ts', async () => {
    await generateRestClient({
      dmmf: makeDocument([USER_MODEL], [ROLE_ENUM]),
      outputDir: tmpDir,
    })

    const userContent = await fs.readFile(path.join(tmpDir, 'user.ts'), 'utf-8')
    expect(userContent).toContain("from './enums'")
    expect(userContent).toContain('Role')
  })

  test('output directory is created if it does not exist', async () => {
    const nested = path.join(tmpDir, 'deep', 'nested', 'output')
    await generateRestClient({ dmmf: makeDocument([POST_MODEL]), outputDir: nested })
    const files = await fs.readdir(nested)
    expect(files).toContain('index.ts')
  })
})

// ─────────────────────────────────────────────────────────────────────────────
// RestApiClientGenerator (manifest)
// ─────────────────────────────────────────────────────────────────────────────

describe('RestApiClientGenerator', () => {
  test('has the correct generator name', () => {
    const gen = new RestApiClientGenerator()
    expect(gen.name).toBe('prisma-rest-api-client')
  })

  test('returns correct manifest', async () => {
    const gen = new RestApiClientGenerator()
    const manifest = await gen.getManifest({ output: null } as any)
    expect(manifest.prettyName).toBe('Prisma REST API Client')
    expect(manifest.defaultOutput).toBe('./generated/rest-client')
    expect(manifest.requiresEngines).toEqual([])
  })
})

