import type * as DMMF from '@prisma/dmmf'
import {
  interfaceDeclaration,
  moduleExport,
  namedType,
  property,
  stringLiteral,
  stringify,
  typeDeclaration,
  unionType,
} from '@prisma/ts-builders'

import { fieldToTsType, getCreateInputFields, getScalarAndEnumFields, getUniqueFields } from './dmmf-helpers'

/**
 * Generates an `export type {EnumName} = 'VALUE_A' | 'VALUE_B'` declaration
 * for a DMMF enum.
 */
export function generateEnumType(dmmfEnum: DMMF.DatamodelEnum): string {
  const variants = dmmfEnum.values.map((v) => stringLiteral(v.name))
  const union = unionType(variants)
  const decl = typeDeclaration(dmmfEnum.name, union)
  return stringify(moduleExport(decl))
}

/**
 * Generates the four TypeScript interfaces that describe a model's shape
 * and its CRUD argument types for a REST API client:
 *
 * - `{Model}` — full model with all scalar/enum fields
 * - `{Model}CreateInput` — fields needed to create a record
 * - `{Model}UpdateInput` — all updatable fields as optional
 * - `{Model}WhereUniqueInput` — identifying fields (@id / @unique) as optional
 */
export function generateModelTypes(model: DMMF.Model): string {
  const parts: string[] = []

  // ── Main model interface ──────────────────────────────────────────────────
  const modelIface = interfaceDeclaration(model.name)
  for (const field of getScalarAndEnumFields(model.fields)) {
    const prop = property(field.name, namedType(fieldToTsType(field)))
    if (!field.isRequired || field.hasDefaultValue || field.isId) {
      prop.optional()
    }
    modelIface.add(prop)
  }
  parts.push(stringify(moduleExport(modelIface)))

  // ── CreateInput ──────────────────────────────────────────────────────────
  const createIface = interfaceDeclaration(`${model.name}CreateInput`)
  for (const field of getCreateInputFields(model.fields)) {
    const prop = property(field.name, namedType(fieldToTsType(field)))
    if (!field.isRequired || field.hasDefaultValue) {
      prop.optional()
    }
    createIface.add(prop)
  }
  parts.push(stringify(moduleExport(createIface)))

  // ── UpdateInput ──────────────────────────────────────────────────────────
  const updateIface = interfaceDeclaration(`${model.name}UpdateInput`)
  for (const field of getCreateInputFields(model.fields)) {
    updateIface.add(property(field.name, namedType(fieldToTsType(field))).optional())
  }
  parts.push(stringify(moduleExport(updateIface)))

  // ── WhereUniqueInput ─────────────────────────────────────────────────────
  const whereIface = interfaceDeclaration(`${model.name}WhereUniqueInput`)
  for (const field of getUniqueFields(model.fields)) {
    whereIface.add(property(field.name, namedType(fieldToTsType(field))).optional())
  }
  parts.push(stringify(moduleExport(whereIface)))

  return parts.join('\n\n')
}

