import fs from 'node:fs/promises'
import os from 'node:os'
import path from 'node:path'

import type * as DMMF from '@prisma/dmmf'
import { afterEach, beforeEach, describe, expect, test } from 'vitest'

import {
  dmmfTypeToTs,
  fieldToTsType,
  getCreateInputFields,
  getScalarAndEnumFields,
  getUniqueFields,
  modelNameToPropertyKey,
  modelNameToResourcePath,
} from '../dmmf-helpers'
import { generateMainClient } from '../generate-main-client'
import { generateModelClient } from '../generate-model-client'
import { generateEnumType, generateModelTypes } from '../generate-model-types'
import { generateRestClient } from '../generate-rest-client'
import { RestApiClientGenerator } from '../generator'

// ─────────────────────────────────────────────────────────────────────────────
// DMMF fixture helpers
// ─────────────────────────────────────────────────────────────────────────────

function makeField(overrides: Partial<DMMF.Field> & Pick<DMMF.Field, 'name' | 'type'>): DMMF.Field {
  return {
    kind: 'scalar',
    isRequired: true,
    isList: false,
    isUnique: false,
    isId: false,
    isReadOnly: false,
    hasDefaultValue: false,
    ...overrides,
  }
}

function makeModel(name: string, fields: DMMF.Field[]): DMMF.Model {
  return {
    name,
    dbName: null,
    schema: null,
    fields,
    uniqueFields: [],
    uniqueIndexes: [],
    primaryKey: null,
  }
}

const USER_MODEL = makeModel('User', [
  makeField({ name: 'id', type: 'Int', isId: true, hasDefaultValue: true, isReadOnly: true }),
  makeField({ name: 'name', type: 'String' }),
  makeField({ name: 'email', type: 'String', isUnique: true }),
  makeField({ name: 'createdAt', type: 'DateTime', hasDefaultValue: true, isUpdatedAt: false }),
  makeField({ name: 'active', type: 'Boolean', isRequired: false, hasDefaultValue: true }),
  makeField({ name: 'role', type: 'Role', kind: 'enum', isRequired: false }),
  // relation field — should be excluded from all interfaces
  makeField({ name: 'posts', type: 'Post', kind: 'object', isList: true, isRequired: false }),
])

const POST_MODEL = makeModel('Post', [
  makeField({ name: 'id', type: 'Int', isId: true, hasDefaultValue: true, isReadOnly: true }),
  makeField({ name: 'title', type: 'String' }),
  makeField({ name: 'authorId', type: 'Int', isReadOnly: true }),
])

const ROLE_ENUM: DMMF.DatamodelEnum = {
  name: 'Role',
  values: [
    { name: 'ADMIN', dbName: null },
    { name: 'USER', dbName: null },
    { name: 'MODERATOR', dbName: null },
  ],
}

// ─────────────────────────────────────────────────────────────────────────────
// dmmf-helpers
// ─────────────────────────────────────────────────────────────────────────────

describe('dmmfTypeToTs', () => {
  test('maps scalar types', () => {
    expect(dmmfTypeToTs('String')).toBe('string')
    expect(dmmfTypeToTs('Int')).toBe('number')
    expect(dmmfTypeToTs('Float')).toBe('number')
    expect(dmmfTypeToTs('Decimal')).toBe('number')
    expect(dmmfTypeToTs('Boolean')).toBe('boolean')
    expect(dmmfTypeToTs('DateTime')).toBe('string')
    expect(dmmfTypeToTs('BigInt')).toBe('bigint')
    expect(dmmfTypeToTs('Json')).toBe('unknown')
    expect(dmmfTypeToTs('Bytes')).toBe('string')
  })

  test('passes enum/unknown types through verbatim', () => {
    expect(dmmfTypeToTs('Role')).toBe('Role')
    expect(dmmfTypeToTs('CustomType')).toBe('CustomType')
  })
})

describe('fieldToTsType', () => {
  test('returns simple type for non-list field', () => {
    expect(fieldToTsType(makeField({ name: 'x', type: 'String' }))).toBe('string')
  })

  test('appends array suffix for list fields', () => {
    expect(fieldToTsType(makeField({ name: 'tags', type: 'String', isList: true }))).toBe('string[]')
  })
})

describe('getScalarAndEnumFields', () => {
  test('excludes object and unsupported fields', () => {
    const fields = getScalarAndEnumFields(USER_MODEL.fields)
    expect(fields.map((f) => f.name)).toEqual(['id', 'name', 'email', 'createdAt', 'active', 'role'])
  })
})

describe('getUniqueFields', () => {
  test('returns @id and @unique scalar/enum fields', () => {
    const fields = getUniqueFields(USER_MODEL.fields)
    expect(fields.map((f) => f.name)).toEqual(['id', 'email'])
  })
})

describe('getCreateInputFields', () => {
  test('excludes readOnly, generated, and @updatedAt fields', () => {
    const fields = getCreateInputFields(USER_MODEL.fields)
    // 'id' is readOnly, 'posts' is object → both excluded
    expect(fields.map((f) => f.name)).toEqual(['name', 'email', 'createdAt', 'active', 'role'])
  })
})

describe('modelNameToResourcePath', () => {
  test('pluralises and kebab-cases model names', () => {
    expect(modelNameToResourcePath('User')).toBe('users')
    expect(modelNameToResourcePath('BlogPost')).toBe('blog-posts')
    expect(modelNameToResourcePath('OrderItem')).toBe('order-items')
  })
})

describe('modelNameToPropertyKey', () => {
  test('camelCases and pluralises model names', () => {
    expect(modelNameToPropertyKey('User')).toBe('users')
    expect(modelNameToPropertyKey('BlogPost')).toBe('blogPosts')
  })
})

// ─────────────────────────────────────────────────────────────────────────────
// generate-model-types
// ─────────────────────────────────────────────────────────────────────────────

describe('generateEnumType', () => {
  test('generates a string literal union type', () => {
    expect(generateEnumType(ROLE_ENUM)).toMatchInlineSnapshot(
      `"export type Role = "ADMIN" | "USER" | "MODERATOR""`,
    )
  })
})

describe('generateModelTypes', () => {
  test('generates all four interfaces for User model', () => {
    const output = generateModelTypes(USER_MODEL)
    expect(output).toMatchInlineSnapshot(`
      "export interface User {
        id?: number
        name: string
        email: string
        createdAt?: string
        active?: boolean
        role?: Role
      }

      export interface UserCreateInput {
        name: string
        email: string
        createdAt?: string
        active?: boolean
        role?: Role
      }

      export interface UserUpdateInput {
        name?: string
        email?: string
        createdAt?: string
        active?: boolean
        role?: Role
      }

      export interface UserWhereUniqueInput {
        id?: number
        email?: string
      }"
    `)
  })

  test('generates empty interfaces when model has no scalar fields', () => {
    const emptyModel = makeModel('Empty', [])
    const output = generateModelTypes(emptyModel)
    expect(output).toMatchInlineSnapshot(`
      "export interface Empty {}

      export interface EmptyCreateInput {}

      export interface EmptyUpdateInput {}

      export interface EmptyWhereUniqueInput {}"
    `)
  })
})

// ─────────────────────────────────────────────────────────────────────────────
// generate-model-client
// ─────────────────────────────────────────────────────────────────────────────

describe('generateModelClient', () => {
  test('generates a REST client class with all five CRUD methods', () => {
    const output = generateModelClient(USER_MODEL)
    // Verify the class structure without being overly sensitive to whitespace
    expect(output).toContain('export class UserRestClient')
    expect(output).toContain('async findMany(')
    expect(output).toContain('async findUnique(')
    expect(output).toContain('async create(')
    expect(output).toContain('async update(')
    expect(output).toContain('async delete(')
  })

  test('uses the kebab-cased resource path in fetch URLs', () => {
    const output = generateModelClient(makeModel('BlogPost', []))
    expect(output).toContain('blog-posts')
  })

  test('throws informative errors on missing where fields', () => {
    const output = generateModelClient(USER_MODEL)
    expect(output).toContain('User.findUnique requires at least one field')
    expect(output).toContain('User.update requires at least one field')
    expect(output).toContain('User.delete requires at least one field')
  })

  test('uses encodeURIComponent for IDs in URLs', () => {
    const output = generateModelClient(USER_MODEL)
    expect(output).toContain('encodeURIComponent(String(id))')
  })
})

// ─────────────────────────────────────────────────────────────────────────────
// generate-main-client
// ─────────────────────────────────────────────────────────────────────────────

describe('generateMainClient', () => {
  test('generates RestApiClient with properties for each model', () => {
    const output = generateMainClient([USER_MODEL, POST_MODEL])
    expect(output).toMatchInlineSnapshot(`
      "export class RestApiClient {
        readonly users: UserRestClient
        readonly posts: PostRestClient

        constructor(baseUrl: string) {
          const normalizedBase = baseUrl.replace(/\\/$/, '')
          this.users = new UserRestClient(normalizedBase)
          this.posts = new PostRestClient(normalizedBase)
        }
      }"
    `)
  })

  test('generates an empty RestApiClient when there are no models', () => {
    expect(generateMainClient([])).toMatchInlineSnapshot(`
      "export class RestApiClient {
        constructor(_baseUrl: string) {}
      }"
    `)
  })
})

// ─────────────────────────────────────────────────────────────────────────────
// generate-rest-client (integration)
// ─────────────────────────────────────────────────────────────────────────────

describe('generateRestClient', () => {
  let tmpDir: string

  beforeEach(async () => {
    tmpDir = await fs.mkdtemp(path.join(os.tmpdir(), 'rest-client-test-'))
  })

  afterEach(async () => {
    await fs.rm(tmpDir, { recursive: true, force: true })
  })

  function makeDocument(models: DMMF.Model[], enums: DMMF.DatamodelEnum[] = []): DMMF.Document {
    return {
      datamodel: { models, enums, types: [], indexes: [] },
      schema: {
        inputObjectTypes: { prisma: [] },
        outputObjectTypes: { prisma: [], model: [] },
        enumTypes: { prisma: [] },
        fieldRefTypes: { prisma: [] },
      },
      mappings: {
        modelOperations: [],
        otherOperations: { read: [], write: [] },
      },
    }
  }

  test('writes index.ts and per-model files', async () => {
    await generateRestClient({
      dmmf: makeDocument([USER_MODEL, POST_MODEL], [ROLE_ENUM]),
      outputDir: tmpDir,
    })

    const files = await fs.readdir(tmpDir)
    expect(files.sort()).toEqual(['enums.ts', 'index.ts', 'post.ts', 'user.ts'])
  })

  test('index.ts re-exports all types and declares RestApiClient', async () => {
    await generateRestClient({
      dmmf: makeDocument([USER_MODEL]),
      outputDir: tmpDir,
    })

    const indexContent = await fs.readFile(path.join(tmpDir, 'index.ts'), 'utf-8')
    expect(indexContent).toContain('export type { User')
    expect(indexContent).toContain('export { UserRestClient }')
    expect(indexContent).toContain('export class RestApiClient')
    expect(indexContent).toContain('readonly users: UserRestClient')
  })

  test('enums.ts is written only when there are enums', async () => {
    await generateRestClient({
      dmmf: makeDocument([POST_MODEL], []),
      outputDir: tmpDir,
    })

    const files = await fs.readdir(tmpDir)
    expect(files).not.toContain('enums.ts')
  })

  test('model file imports enum types from enums.ts', async () => {
    await generateRestClient({
      dmmf: makeDocument([USER_MODEL], [ROLE_ENUM]),
      outputDir: tmpDir,
    })

    const userContent = await fs.readFile(path.join(tmpDir, 'user.ts'), 'utf-8')
    expect(userContent).toContain("from './enums'")
    expect(userContent).toContain('Role')
  })

  test('output directory is created if it does not exist', async () => {
    const nested = path.join(tmpDir, 'deep', 'nested', 'output')
    await generateRestClient({ dmmf: makeDocument([POST_MODEL]), outputDir: nested })
    const files = await fs.readdir(nested)
    expect(files).toContain('index.ts')
  })
})

